import{_ as e,o as l,c as t,a2 as r}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F05: 應收帳款品質與收款天數 - 財務審計專家報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6261_久元/20260512/F05_應收帳款品質與收款天數.md","filePath":"審計報告庫/財務審計/6261_久元/20260512/F05_應收帳款品質與收款天數.md"}'),i={name:"審計報告庫/財務審計/6261_久元/20260512/F05_應收帳款品質與收款天數.md"};function o(h,a,n,s,d,c){return l(),t("div",null,[...a[0]||(a[0]=[r('<h1 id="f05-應收帳款品質與收款天數-財務審計專家報告" tabindex="-1">F05: 應收帳款品質與收款天數 - 財務審計專家報告 <a class="header-anchor" href="#f05-應收帳款品質與收款天數-財務審計專家報告" aria-label="Permalink to &quot;F05: 應收帳款品質與收款天數 - 財務審計專家報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>應收帳款的品質如何？收款天數的變化與產業慣例的差距是否在合理範圍？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：DSO 86→114天AR+30.8%營收-0.9%背離。逾期&gt;180天9,773萬佔7.6%。收款品質下滑客戶付款惡化</li><li><strong>風險評級</strong>：高</li><li><strong>數據時效</strong>：截至2025年合併財報及附註</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>重點數據</strong>：AR 10.72→12.83億(年增30.8%)。DSO 86→114天(+33%)與營收-0.9%嚴重背離。逾期&gt;180天9,773萬佔AR 7.6%。關係人AR 9,523萬DSO&gt;700天異常。備抵4,082萬備抵率3.2%vs逾期11.5%。營收萎縮但應收膨脹，轉現金力大幅下滑為明確惡化訊號。</li><li><strong>診斷見解</strong>：DSO三年惡化+33%反映收款效率持續下滑，逾半年AR高達9,773萬若無法回收EPS損失0.76元，營運資金壓力疊加存貨問題形成雙重資金佔用。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="dso趨勢與營運資金壓力" tabindex="-1">DSO趨勢與營運資金壓力 <a class="header-anchor" href="#dso趨勢與營運資金壓力" aria-label="Permalink to &quot;DSO趨勢與營運資金壓力&quot;">​</a></h3><p>DSO從86→114天3年最高，逐季惡化。Q1~100→Q4 114天，下半年收款加速放緩。營收從Q3 10.6→Q4 11.8億但AR從11.8→12.8億，額外佔用營運資金1.0億。DSO 114天對測試代工+設備尚可接受(同業90-120天)，但+33%方向為負面。CCC同樣惡化423→514→484天。</p><h3 id="逾期ar分析" tabindex="-1">逾期AR分析 <a class="header-anchor" href="#逾期ar分析" aria-label="Permalink to &quot;逾期AR分析&quot;">​</a></h3><p>1.47億逾期中&gt;180天9,773萬佔66%，已按36.5%提列備抵3,569萬，剩餘6,204萬仍列AR淨額。若無法回收額外損失6,204萬(EPS 0.48元)。關係人AR(宏齊9,342萬)同屬&gt;180天群，可能為大額來源。</p><h3 id="備抵充足性" tabindex="-1">備抵充足性 <a class="header-anchor" href="#備抵充足性" aria-label="Permalink to &quot;備抵充足性&quot;">​</a></h3><p>備抵率3.2%vs逾期率11.5%。理論加權備抵約3,958萬與實際4,082萬接近，提列充足。但風險在經濟惡化時未逾期AR轉逾期需追加備抵。</p><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><h3 id="🔴-空方觀點" tabindex="-1">🔴 空方觀點 <a class="header-anchor" href="#🔴-空方觀點" aria-label="Permalink to &quot;🔴 空方觀點&quot;">​</a></h3><ol><li>DSO 86→114天+33%，AR+30.8%與營收衰退背離，若續惡化將額外佔用營運資金1-2億</li><li>逾期&gt;180天9,773萬約當EPS 0.76元，已提備抵3,569萬但剩餘6,204萬若轉呆帳直接侵蝕</li><li>關係人AR 9,523萬(DSO&gt;700天)實質隱性資金貸與，集中風險極高</li></ol><h3 id="🟢-多方觀點" tabindex="-1">🟢 多方觀點 <a class="header-anchor" href="#🟢-多方觀點" aria-label="Permalink to &quot;🟢 多方觀點&quot;">​</a></h3><ol><li>備抵4,082萬與預期損失模型一致，會計透明</li><li>88.5% AR未逾期，大額逾期集中在少數客戶，針對性處理可回收</li><li>DSO 114天對比同業(京元68天,精測100-120天)在行業區間內</li></ol><h3 id="⚖️-綜合權衡" tabindex="-1">⚖️ 綜合權衡 <a class="header-anchor" href="#⚖️-綜合權衡" aria-label="Permalink to &quot;⚖️ 綜合權衡&quot;">​</a></h3><p>AR品質2025年顯著惡化。DSO+33%與營收背離為核心警訊。9,773萬&gt;180天AR若2026 Q2財報仍列逾期應視為呆帳。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>計算工具：財務分析工具.py(receivable_check 6261 2023 2025)</li><li>年報附註：2025 Q4合併財報第34-35頁</li><li>數據查詢日期：2026-05-12</li></ul>',23)])])}const b=e(i,[["render",o]]);export{u as __pageData,b as default};
